import React, { useState, useEffect } from 'react';
import { LogoIcon } from './icons/LogoIcon';
import { ProfileType } from '../App';

interface HeaderProps {
  profile: ProfileType;
  toggleProfile: () => void;
  data: any;
}

const navLinks = [
    {name: 'Home', href: '#home'}, 
    {name: 'About', href: '#about'},
    {name: 'Services', href: '#services'},
    {name: 'Portfolio', href: '#portfolio'},
    {name: 'Gallery', href: '#gallery'},
    {name: 'Blog', href: '#blog'},
    {name: 'Contact', href: '#contact'}
];

const MenuIcon = () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <line x1="3" y1="12" x2="21" y2="12"></line>
        <line x1="3" y1="6" x2="21" y2="6"></line>
        <line x1="3" y1="18" x2="21" y2="18"></line>
    </svg>
);

const CloseIcon = () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <line x1="18" y1="6" x2="6" y2="18"></line>
        <line x1="6" y1="6" x2="18" y2="18"></line>
    </svg>
);

const Header: React.FC<HeaderProps> = ({ profile, toggleProfile, data }) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    if (isMobileMenuOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
    return () => {
        document.body.style.overflow = 'unset';
    }
  }, [isMobileMenuOpen]);

  const handleNavClick = (e: React.MouseEvent<HTMLAnchorElement>) => {
    e.preventDefault();
    setIsMobileMenuOpen(false);
    const href = e.currentTarget.getAttribute('href');
    if (!href) return;
    const targetId = href.substring(1);
    const targetElement = document.getElementById(targetId);
    if (targetElement) {
        targetElement.scrollIntoView({ behavior: 'smooth' });
    }
  };

  return (
    <header className="py-6 px-4 md:px-8 lg:px-16 sticky top-0 z-50 bg-black/80 backdrop-blur-sm transition-all duration-300">
      <div className="container mx-auto flex justify-between items-center">
        <a href="#home" onClick={handleNavClick} className="flex items-center gap-3 relative z-50">
          <LogoIcon color={data.color.primary} />
          <span className="text-2xl font-bold text-white">{data.logoName}</span>
        </a>

        {/* Desktop Nav */}
        <nav className="hidden lg:flex items-center gap-8">
          {navLinks.map((link) => (
            <a key={link.name} href={link.href} onClick={handleNavClick} className="text-gray-300 hover:text-white transition-colors duration-300">
              {link.name}
            </a>
          ))}
        </nav>

        <div className="hidden lg:flex items-center gap-4">
            <button 
              onClick={toggleProfile} 
              className={`${data.color.bg} text-black font-semibold px-6 py-3 rounded-full hover:bg-opacity-80 transition-all duration-300 text-sm`}
              aria-label={`Switch to ${profile === 'mustafa' ? 'Kaptaan Hermes' : 'Mohammed Mustafa'} profile`}
            >
                Toggle Profile
            </button>
        </div>

        {/* Mobile Menu Button */}
        <button
            className="lg:hidden text-white relative z-50 p-2"
            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
            aria-label="Toggle menu"
        >
             {isMobileMenuOpen ? <CloseIcon /> : <MenuIcon />}
        </button>

         {/* Mobile Nav Overlay */}
         <div className={`fixed inset-0 bg-black/95 z-40 flex flex-col items-center justify-center gap-8 transition-all duration-300 lg:hidden ${isMobileMenuOpen ? 'opacity-100 visible' : 'opacity-0 invisible pointer-events-none'}`}>
             <nav className="flex flex-col items-center gap-6">
                {navLinks.map((link) => (
                    <a key={link.name} href={link.href} onClick={handleNavClick} className="text-2xl font-bold text-gray-300 hover:text-white transition-colors duration-300">
                    {link.name}
                    </a>
                ))}
            </nav>
            <div className="flex flex-col gap-4 mt-4">
                <button 
                onClick={() => { toggleProfile(); setIsMobileMenuOpen(false); }} 
                className={`${data.color.bg} text-black font-semibold px-8 py-3 rounded-full hover:bg-opacity-80 transition-all duration-300 text-lg`}
                >
                    Switch Profile
                </button>
                 <a href="#/login" onClick={() => setIsMobileMenuOpen(false)} className="text-gray-500 hover:text-white text-sm text-center">Admin Login</a>
            </div>
        </div>
      </div>
    </header>
  );
};

export default Header;

import React, { useRef, useState, useEffect, useCallback } from 'react';

interface GalleryItem {
  imageUrl: string;
  title: string;
}

interface GalleryProps {
  data: {
    gallery: {
      subheading: string;
      heading:string;
      items: GalleryItem[];
    };
    color: {
      text: string;
    };
  };
}

const Gallery: React.FC<GalleryProps> = ({ data }) => {
  const { gallery, color } = data;
  const sliderRef = useRef<HTMLDivElement>(null);
  const requestRef = useRef<number | undefined>(undefined);

  const [isDown, setIsDown] = useState(false);
  const [startX, setStartX] = useState(0);
  const [scrollLeft, setScrollLeft] = useState(0);

  if (!gallery || !gallery.items || gallery.items.length === 0) {
    return null;
  }

  // Duplicate items for a seamless loop
  const fullList = [...gallery.items, ...gallery.items];

  const animateScroll = useCallback(() => {
    if (sliderRef.current && !isDown) {
      sliderRef.current.scrollLeft += 1.5;
      if (sliderRef.current.scrollLeft >= (sliderRef.current.scrollWidth / 2)) {
        sliderRef.current.scrollLeft -= (sliderRef.current.scrollWidth / 2);
      }
    }
  }, [isDown]);

  const stopAnimateScroll = useCallback(() => {
      if (requestRef.current) {
          cancelAnimationFrame(requestRef.current);
          requestRef.current = undefined;
      }
  }, []);

  const startAnimateScroll = useCallback(() => {
      stopAnimateScroll();
      const loop = () => {
        animateScroll();
        requestRef.current = requestAnimationFrame(loop);
      }
      requestRef.current = requestAnimationFrame(loop);
  }, [animateScroll, stopAnimateScroll]);

  useEffect(() => {
    startAnimateScroll();
    return () => stopAnimateScroll();
  }, [startAnimateScroll, stopAnimateScroll]);

  const handleMouseDown = (e: React.MouseEvent<HTMLDivElement>) => {
    setIsDown(true);
    sliderRef.current?.classList.add('active');
    setStartX(e.pageX - (sliderRef.current?.offsetLeft ?? 0));
    setScrollLeft(sliderRef.current?.scrollLeft ?? 0);
    stopAnimateScroll();
  };

  const handleMouseLeave = () => {
    setIsDown(false);
    sliderRef.current?.classList.remove('active');
    startAnimateScroll();
  };

  const handleMouseUp = () => {
    setIsDown(false);
    sliderRef.current?.classList.remove('active');
    startAnimateScroll();
  };

  const handleMouseEnter = () => {
    stopAnimateScroll();
  };

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!isDown) return;
    e.preventDefault();
    const x = e.pageX - (sliderRef.current?.offsetLeft ?? 0);
    const walk = (x - startX) * 3; // scroll-fast multiplier
    if (sliderRef.current) {
      sliderRef.current.scrollLeft = scrollLeft - walk;
    }
  };

  const handleTouchStart = () => {
      setIsDown(true);
      stopAnimateScroll();
  };

  const handleTouchEnd = () => {
      setIsDown(false);
      startAnimateScroll();
  };

  return (
    <section id="gallery" className="py-20 bg-[#111111] overflow-hidden">
      <div className="container mx-auto px-4 md:px-8 lg:px-16">
        <div className="text-left mb-12">
            <p className={`${color.text} font-semibold mb-2`}>{gallery.subheading}</p>
            <h2 className="text-4xl md:text-5xl font-extrabold text-white">{gallery.heading}</h2>
        </div>
      </div>
      <div 
        className="w-full flex overflow-x-auto cursor-grab select-none gallery-slider"
        ref={sliderRef}
        onMouseDown={handleMouseDown}
        onMouseLeave={handleMouseLeave}
        onMouseUp={handleMouseUp}
        onMouseMove={handleMouseMove}
        onMouseEnter={handleMouseEnter}
        onTouchStart={handleTouchStart}
        onTouchEnd={handleTouchEnd}
      >
        {fullList.map((item, index) => (
           <div key={index} className="mx-4 shrink-0">
                <img 
                    src={item.imageUrl} 
                    alt={item.title} 
                    className="h-64 w-auto object-cover rounded-lg shadow-lg pointer-events-none" 
                />
            </div>
        ))}
      </div>
    </section>
  );
};

export default Gallery;

