const Header: React.FC<HeaderProps> = ({ profile, toggleProfile, data }) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    if (isMobileMenuOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
    return () => {
        document.body.style.overflow = 'unset';
    }
  }, [isMobileMenuOpen]);

  const handleNavClick = (e: React.MouseEvent<HTMLAnchorElement>) => {
    e.preventDefault();
    setIsMobileMenuOpen(false);
    const href = e.currentTarget.getAttribute('href');
    if (!href) return;
    const targetId = href.substring(1);
    const targetElement = document.getElementById(targetId);
    if (targetElement) {
        targetElement.scrollIntoView({ behavior: 'smooth' });
    }
  };

  return (
    <header className="py-6 px-4 md:px-8 lg:px-16 sticky top-0 z-50 bg-black/80 backdrop-blur-sm transition-all duration-300">
      <div className="container mx-auto flex justify-between items-center">
        <a href="#home" onClick={handleNavClick} className="flex items-center gap-3 relative z-50">
          <LogoIcon color={data.color.primary} />
          <span className="text-2xl font-bold text-white">{data.logoName}</span>
        </a>

        {/* Desktop Nav */}
        <nav className="hidden xl:flex items-center gap-6">
          {navLinks.map((link) => (
            <a key={link.name} href={link.href} onClick={handleNavClick} className="text-gray-300 hover:text-white transition-colors duration-300 text-sm font-medium">
              {link.name}
            </a>
          ))}
        </nav>

        <div className="hidden xl:flex items-center gap-4">
            <button 
              onClick={toggleProfile} 
              className={`${data.color.bg} text-black font-semibold px-6 py-3 rounded-full hover:bg-opacity-80 transition-all duration-300 text-sm`}
              aria-label={`Switch to ${profile === 'mustafa' ? 'Kaptaan Hermes' : 'Mohammed Mustafa'} profile`}
            >
                Toggle Profile
            </button>
        </div>

        {/* Mobile Menu Button */}
        <button
            className="xl:hidden text-white relative z-50 p-2"
            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
            aria-label="Toggle menu"
        >
             {isMobileMenuOpen ? <CloseIcon /> : <MenuIcon />}
        </button>

         {/* Mobile Nav Overlay */}
         <div className={`fixed inset-0 bg-black/95 z-40 flex flex-col items-center justify-center gap-8 transition-all duration-300 xl:hidden ${isMobileMenuOpen ? 'opacity-100 visible' : 'opacity-0 invisible pointer-events-none'}`}>
             <nav className="flex flex-col items-center gap-6">
                {navLinks.map((link) => (
                    <a key={link.name} href={link.href} onClick={handleNavClick} className="text-2xl font-bold text-gray-300 hover:text-white transition-colors duration-300">
                    {link.name}
                    </a>
                ))}
            </nav>
            <div className="flex flex-col gap-4 mt-4">
                <button 
                onClick={() => { toggleProfile(); setIsMobileMenuOpen(false); }} 
                className={`${data.color.bg} text-black font-semibold px-8 py-3 rounded-full hover:bg-opacity-80 transition-all duration-300 text-lg`}
                >
                    Switch Profile
                </button>
                 <a href="#/login" onClick={() => setIsMobileMenuOpen(false)} className="text-gray-500 hover:text-white text-sm text-center">Admin Login</a>
            </div>
        </div>
      </div>
    </header>
  );
};

