// NOTE: Service icons are hardcoded above and are not part of the editable data below.
// To add a new service with a new icon, you would need to add the icon component manually.
export const data = ${JSON.stringify(
      {
        mustafa: { ...localData.mustafa, services: { ...localData.mustafa.services, items: originalMustafaServices } },
        hermes: { ...localData.hermes, services: { ...localData.hermes.services, items: originalHermesServices } },
      },
      (key, value) => {
        if (key === 'icon') return 'ICON_PLACEHOLDER';
        return value;
      },
      2
    ).replace(/"icon": "ICON_PLACEHOLDER"/g, 'icon: () => null')};
`;
    // Clean up placeholder functions to be actual component references
    let finalString = fileContent;
    originalMustafaServices.forEach((item: any) => {
      finalString = finalString.replace(`"title": "${item.title}",\n          "icon": () => null`, `"title": "${item.title}",\n          "icon": ${item.icon.name}`);
    });
    originalHermesServices.forEach((item: any) => {
        finalString = finalString.replace(`"title": "${item.title}",\n          "icon": () => null`, `"title": "${item.title}",\n          "icon": ${item.icon.name}`);
    });


    const blob = new Blob([finalString], { type: 'text/typescript' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'data.ts';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const renderContent = () => {
    const props = {
        mustafaData: localData.mustafa,
        hermesData: localData.hermes,
        onUpdate: handleUpdate
    };
